     1→/**
     2→ * MMS Service Demand Service
     3→ *
     4→ * Manages fleet availability requirements - a CRITICAL v2.1 service.
     5→ * Service demand is a HARD CONSTRAINT for the optimizer: schedules that
     6→ * violate minimum train availability must be rejected.
     7→ *
     8→ * Key responsibilities:
     9→ * - Define minimum train requirements by fleet, day type, and time period
    10→ * - Validate that proposed PM schedules don't violate availability
    11→ * - Calculate default demand (85% of fleet) when no explicit config exists
    12→ * - Support peak period requirements (AM, midday, PM, evening)
    13→ *
    14→ * Business rules:
    15→ * - Optimizer CANNOT schedule PM that would drop fleet below minTrainsRequired
    16→ * - Day types: WEEKDAY, SATURDAY, SUNDAY, HOLIDAY
    17→ * - Demand records are versioned by effectiveDate (most recent applies)
    18→ * - Peak period requirements are optional but enforced if defined
    19→ *
    20→ * @see specs/003-database-schema.md Section 3.2.1 (Service Demand)
    21→ * @see specs/004-domain-services.md Section 4.2.6 (Service Demand Service)
    22→ */
    23→
    24→import { eq, and, sql, desc, lte, count, inArray, gte } from 'drizzle-orm';
    25→import type { SQL } from 'drizzle-orm';
    26→import { BaseService, MmsAttributes } from '../lib/services/base';
    27→import {
    28→  serviceDemand,
    29→  trains,
    30→  fleets,
    31→  pmSchedule,
    32→  type ServiceDemand,
    33→  type NewServiceDemand,
    34→} from '../lib/db/schema';
    35→import {
    36→  NotFoundError,
    37→  ValidationError,
    38→  DuplicateError,
    39→} from '../lib/errors';
    40→
    41→// =============================================================================
    42→// Types
    43→// =============================================================================
    44→
    45→/** Day type enum values */
    46→export type DayType = 'WEEKDAY' | 'SATURDAY' | 'SUNDAY' | 'HOLIDAY';
    47→
    48→/** Time period for peak requirements */
    49→export type TimePeriod = 'PEAK_AM' | 'MIDDAY' | 'PEAK_PM' | 'EVENING' | 'ALL_DAY';
    50→
    51→/** Demand configuration for a specific fleet/date */
    52→export interface DemandConfig {
    53→  fleetId: string;
    54→  fleetCode: string;
    55→  date: string;
    56→  dayType: DayType;
    57→  minTrainsRequired: number;
    58→  standbyBuffer: number;
    59→  totalRequired: number; // minTrainsRequired + standbyBuffer
    60→  peakAmRequirement: number | null;
    61→  middayRequirement: number | null;
    62→  peakPmRequirement: number | null;
    63→  eveningRequirement: number | null;
    64→  source: 'CONFIG' | 'DEFAULT';
    65→  sourceRecord: ServiceDemand | null;
    66→}
    67→
    68→/** Availability validation result */
    69→export interface AvailabilityValidation {
    70→  isValid: boolean;
    71→  fleetId: string;
    72→  date: string;
    73→  dayType: DayType;
    74→  totalTrains: number;
    75→  fitTrains: number;
    76→  unavailableTrains: number;
    77→  inMaintenanceTrains: number;
