   154→
   155→/** Default standby buffer */
   156→const DEFAULT_STANDBY_BUFFER = 2;
   157→
   158→/** Warning threshold: < this % surplus triggers warning */
   159→const WARNING_THRESHOLD_PCT = 0.10;
